// RUN: %clang_cc1 -triple aarch64-linux-gnu -emit-llvm -O2 %s -o - | FileCheck %s
//
// Verify that output constraints with broader memory alternatives ('o',
// offsettable memory) do not generate the dual-path callbr IR. The backend's
// MayFoldRegister mechanism -- which enables the register-preference
// optimization -- only activates for the literal 'm' code. Emitting "=ro" as a
// direct output would cause the backend to select 'o' (C_Memory) for a
// non-indirect operand and hit an assertion.


// CHECK-LABEL: define dso_local i64 @test_ro_output(
// CHECK-SAME: ) local_unnamed_addr #[[ATTR0:[0-9]+]] {
// CHECK-NEXT:  [[ENTRY:.*:]]
// CHECK-NEXT:    [[X:%.*]] = alloca i64, align 8
// CHECK-NEXT:    call void @llvm.lifetime.start.p0(ptr nonnull [[X]]) #[[ATTR2:[0-9]+]]
// CHECK-NEXT:    call void asm "# $$0", "=*ro"(ptr nonnull elementtype(i64) [[X]]) #[[ATTR2]], !srcloc [[META6:![0-9]+]]
// CHECK-NEXT:    [[TMP0:%.*]] = load i64, ptr [[X]], align 8, !tbaa [[LONG_TBAA7:![0-9]+]]
// CHECK-NEXT:    call void @llvm.lifetime.end.p0(ptr nonnull [[X]]) #[[ATTR2]]
// CHECK-NEXT:    ret i64 [[TMP0]]
//
unsigned long test_ro_output(void) {
  unsigned long x;
  asm("# $0" : "=ro"(x));
  return x;
}
